queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?baggageclaims a :BaggageClaims .
    ?baggageclaims p:HandlerName ?handlername .
    ?baggageclaims p:location ?location_f .
    FILTER(STR(?location_f) = "Terminal 2")
    BIND(?handlername AS ?o0)
  }
  UNION
  {
    ?securitychecks a :SecurityChecks .
    ?securitychecks p:OfficerName ?officername .
    ?securitychecks p:location ?location_f .
    FILTER(STR(?location_f) = "Terminal 2")
    BIND(?officername AS ?o0)
  }
}

